package handlers

import (
	"encoding/json"
	"net/http"
)

type FailureReason string

const (
	ReasonValidationFailed FailureReason = "VALIDATION_FAILED"
	ReasonInternalError    FailureReason = "INTERNAL_ERROR"
)

type SuccessEnvelope[T any] struct {
	OK     bool `json:"ok"`
	Result T    `json:"result"`
}

type FailureEnvelope struct {
	OK     bool   `json:"ok"`
	Reason string `json:"reason"`
}

func WriteResult[T any](w http.ResponseWriter, statusCode int, result T) error {
	return writeJSON(w, statusCode, SuccessEnvelope[T]{
		OK:     true,
		Result: result,
	})
}

func WriteFailure(w http.ResponseWriter, statusCode int, reason FailureReason) error {
	return writeJSON(w, statusCode, FailureEnvelope{
		OK:     false,
		Reason: string(reason),
	})
}

func WriteBusinessFailure(w http.ResponseWriter, reason FailureReason) error {
	return WriteFailure(w, http.StatusOK, reason)
}

func writeJSON(w http.ResponseWriter, statusCode int, payload any) error {
	body, err := json.Marshal(payload)
	if err != nil {
		return err
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(statusCode)
	_, err = w.Write(append(body, '\n'))
	return err
}

package handlers

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"
)

func TestWriteResult(t *testing.T) {
	recorder := httptest.NewRecorder()

	err := WriteResult(recorder, http.StatusCreated, map[string]int{"value": 7})
	if err != nil {
		t.Fatalf("WriteResult returned error: %v", err)
	}

	if recorder.Code != http.StatusCreated {
		t.Fatalf("expected status 201, got %d", recorder.Code)
	}

	if contentType := recorder.Header().Get("Content-Type"); contentType != "application/json" {
		t.Fatalf("expected application/json content type, got %q", contentType)
	}

	var response SuccessEnvelope[map[string]int]
	if err := json.Unmarshal(recorder.Body.Bytes(), &response); err != nil {
		t.Fatalf("decode response: %v", err)
	}

	if !response.OK {
		t.Fatalf("expected ok=true, got false")
	}

	if response.Result["value"] != 7 {
		t.Fatalf("expected result value 7, got %d", response.Result["value"])
	}
}

func TestWriteBusinessFailure(t *testing.T) {
	recorder := httptest.NewRecorder()

	err := WriteBusinessFailure(recorder, ReasonValidationFailed)
	if err != nil {
		t.Fatalf("WriteBusinessFailure returned error: %v", err)
	}

	if recorder.Code != http.StatusOK {
		t.Fatalf("expected status 200, got %d", recorder.Code)
	}

	var response FailureEnvelope
	if err := json.Unmarshal(recorder.Body.Bytes(), &response); err != nil {
		t.Fatalf("decode response: %v", err)
	}

	if response.OK {
		t.Fatalf("expected ok=false, got true")
	}

	if response.Reason != string(ReasonValidationFailed) {
		t.Fatalf("expected reason %q, got %q", ReasonValidationFailed, response.Reason)
	}
}

package statshandlers

import (
	"net/http"
	"socialpredict/handlers"
	configsvc "socialpredict/internal/service/config"
	"socialpredict/models"

	"gorm.io/gorm"
)

type FinancialStats struct {
	TotalMoney              int64 `json:"totalMoney"`
	TotalDebtExtended       int64 `json:"totalDebtExtended"`
	TotalDebtUtilized       int64 `json:"totalDebtUtilized"`
	TotalFeesCollected      int64 `json:"totalFeesCollected"`
	TotalBonusesPaid        int64 `json:"totalBonusesPaid"`
	OutstandingPayouts      int64 `json:"outstandingPayouts"`
	TotalMoneyInCirculation int64 `json:"totalMoneyInCirculation"` // Money currently active in bets
}

type SetupConfiguration struct {
	InitialMarketProbability   float64 `json:"initialMarketProbability"`
	InitialMarketSubsidization int64   `json:"initialMarketSubsidization"`
	InitialMarketYes           int64   `json:"initialMarketYes"`
	InitialMarketNo            int64   `json:"initialMarketNo"`
	CreateMarketCost           int64   `json:"createMarketCost"`
	TraderBonus                int64   `json:"traderBonus"`
	InitialAccountBalance      int64   `json:"initialAccountBalance"`
	MaximumDebtAllowed         int64   `json:"maximumDebtAllowed"`
	MinimumBet                 int64   `json:"minimumBet"`
	MaxDustPerSale             int64   `json:"maxDustPerSale"`
	InitialBetFee              int64   `json:"initialBetFee"`
	BuySharesFee               int64   `json:"buySharesFee"`
	SellSharesFee              int64   `json:"sellSharesFee"`
}

type StatsResponse struct {
	FinancialStats     FinancialStats     `json:"financialStats"`
	SetupConfiguration SetupConfiguration `json:"setupConfiguration"`
}

const reasonStatsUnavailable handlers.FailureReason = "STATS_UNAVAILABLE"

// StatsHandler handles requests for both financial stats and setup configuration.
func StatsHandler(db *gorm.DB, configService configsvc.Service) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if db == nil {
			_ = handlers.WriteFailure(w, http.StatusInternalServerError, reasonStatsUnavailable)
			return
		}
		if configService == nil {
			_ = handlers.WriteFailure(w, http.StatusInternalServerError, reasonStatsUnavailable)
			return
		}

		financialStats, err := calculateFinancialStats(db, configService)
		if err != nil {
			_ = handlers.WriteFailure(w, http.StatusInternalServerError, reasonStatsUnavailable)
			return
		}

		setupConfig := loadSetupConfiguration(configService.Current())

		response := StatsResponse{
			FinancialStats:     financialStats,
			SetupConfiguration: setupConfig,
		}

		if err := handlers.WriteResult(w, http.StatusOK, response); err != nil {
			_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
		}
	}
}

func calculateFinancialStats(db *gorm.DB, configService configsvc.Service) (FinancialStats, error) {
	var result FinancialStats

	totalMoney, err := calculateTotalMoney(db, configService.Current())
	if err != nil {
		return result, err
	}
	result.TotalMoney = totalMoney

	result.TotalDebtExtended = 0
	result.TotalDebtUtilized = 0
	result.TotalFeesCollected = 0
	result.TotalBonusesPaid = 0
	result.OutstandingPayouts = 0
	result.TotalMoneyInCirculation = 0

	return result, nil
}

func calculateTotalMoney(db *gorm.DB, economicConfig *configsvc.AppConfig) (int64, error) {
	var userCount int64
	if err := db.Model(&models.User{}).Where("user_type = ?", "REGULAR").Count(&userCount).Error; err != nil {
		return 0, err
	}

	totalMoney := economicConfig.Economics.User.InitialAccountBalance * userCount
	return totalMoney, nil
}

func loadSetupConfiguration(economicConfig *configsvc.AppConfig) SetupConfiguration {
	var result SetupConfiguration

	result.InitialMarketProbability = economicConfig.Economics.MarketCreation.InitialMarketProbability
	result.InitialMarketSubsidization = economicConfig.Economics.MarketCreation.InitialMarketSubsidization
	result.InitialMarketYes = economicConfig.Economics.MarketCreation.InitialMarketYes
	result.InitialMarketNo = economicConfig.Economics.MarketCreation.InitialMarketNo
	result.CreateMarketCost = economicConfig.Economics.MarketIncentives.CreateMarketCost
	result.TraderBonus = economicConfig.Economics.MarketIncentives.TraderBonus
	result.InitialAccountBalance = economicConfig.Economics.User.InitialAccountBalance
	result.MaximumDebtAllowed = economicConfig.Economics.User.MaximumDebtAllowed
	result.MinimumBet = economicConfig.Economics.Betting.MinimumBet
	result.MaxDustPerSale = economicConfig.Economics.Betting.MaxDustPerSale
	result.InitialBetFee = economicConfig.Economics.Betting.BetFees.InitialBetFee
	result.BuySharesFee = economicConfig.Economics.Betting.BetFees.BuySharesFee
	result.SellSharesFee = economicConfig.Economics.Betting.BetFees.SellSharesFee

	return result
}

package errors

import (
	"encoding/json"
	"log"
	"net/http"
)

// HTTPErrorResponse represents a structured error response.
type HTTPErrorResponse struct {
	Error string `json:"error"`
}

// HandleHTTPError checks for an error and handles it by sending an appropriate HTTP response.
// It logs the error and writes a corresponding HTTP status code and error message to the response writer.
// Returns true if there was an error handled, false otherwise.
func HandleHTTPError(w http.ResponseWriter, err error, statusCode int, userMessage string) bool {
	if err != nil {
		log.Printf("Error: %v", err) // Log the actual error for server-side diagnostics.
		w.WriteHeader(statusCode)
		json.NewEncoder(w).Encode(HTTPErrorResponse{Error: userMessage})
		return true
	}
	return false
}

package auth

import (
	"net/http"
	"strings"

	dusers "socialpredict/internal/domain/users"
)

// Authenticator exposes the authentication operations used by HTTP handlers.
type Authenticator interface {
	CurrentUser(r *http.Request) (*dusers.User, *HTTPError)
	RequireUser(r *http.Request) (*dusers.User, *HTTPError)
	RequireAdmin(r *http.Request) (*dusers.User, *HTTPError)
}

// AuthService provides a façade over the authentication helpers so callers can
// depend on a single injected object rather than package-level functions.
type AuthService struct {
	users dusers.ServiceInterface
}

// NewAuthService constructs a façade that uses the provided users service for
// token validation and password-change enforcement.
func NewAuthService(users dusers.ServiceInterface) *AuthService {
	return &AuthService{users: users}
}

// CurrentUser returns the authenticated user, ensuring any password-change
// requirements are enforced.
func (a *AuthService) CurrentUser(r *http.Request) (*dusers.User, *HTTPError) {
	return ValidateUserAndEnforcePasswordChangeGetUser(r, a.users)
}

// RequireUser resolves the authenticated user without checking the
// must-change-password flag.
func (a *AuthService) RequireUser(r *http.Request) (*dusers.User, *HTTPError) {
	return ValidateTokenAndGetUser(r, a.users)
}

// RequireAdmin ensures the current user is authenticated and has admin privileges.
func (a *AuthService) RequireAdmin(r *http.Request) (*dusers.User, *HTTPError) {
	user, err := a.RequireUser(r)
	if err != nil {
		return nil, err
	}

	if strings.ToUpper(user.UserType) != "ADMIN" {
		return nil, &HTTPError{
			StatusCode: http.StatusForbidden,
