func TestPasswordValidation(t *testing.T) {
	tests := []struct {
		name          string
		currentPass   string
		newPass       string
		expectedValid bool
		expectedError string
	}{
		{
			name:          "Valid password change",
			currentPass:   "oldPassword123!",
			newPass:       "newPassword456!",
			expectedValid: true,
		},
		{
			name:          "Empty current password",
			currentPass:   "",
			newPass:       "newPassword456!",
			expectedValid: false,
			expectedError: "Current password is required",
		},
		{
			name:          "Empty new password",
			currentPass:   "oldPassword123!",
			newPass:       "",
			expectedValid: false,
			expectedError: "New password is required",
		},
		{
			name:          "Weak new password",
			currentPass:   "oldPassword123!",
			newPass:       "weak",
			expectedValid: false,
			expectedError: "does not meet security requirements",
		},
		{
			name:          "Password without numbers",
			currentPass:   "oldPassword123!",
			newPass:       "NoNumbers!",
			expectedValid: false,
			expectedError: "does not meet security requirements",
		},
		{
			name:          "Password without uppercase",
			currentPass:   "oldPassword123!",
			newPass:       "nouppercasepass123",
			expectedValid: false,
			expectedError: "does not meet security requirements",
		},
		{
			name:          "Password too short",
			currentPass:   "oldPassword123!",
			newPass:       "Short1!",
